/** Export des fichiers pour commit GitHub manuel */
async function exportForCommit() {
  try {
    const ref = await _getEmbeddedRef();
    const eng = await _getEmbeddedEngineSource();

    function _download(filename, content, mime) {
      const blob = new Blob([content], { type: mime });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      setTimeout(() => URL.revokeObjectURL(url), 1000);
    }

    _download('ngap_referentiel_2026.json', JSON.stringify(ref, null, 2), 'application/json');
    setTimeout(() => {
      _download('ngap_engine.js', eng, 'application/javascript');
    }, 500);
    _toast('success', 'Fichiers exportés',
      'À commiter dans le repo GitHub (dossier ngap-engine/).');
    return { ok: true };
  } catch (e) {
    return { ok: false, error: e.message };
  }
}

