/* ── Bootstrap automatique au chargement ───────────────────────── */
/*  Appelé AVANT que index.html ne fetch le JSON statique — si le
    script est placé correctement dans l'ordre de chargement, le front
    utilisera la version IDB plutôt que le fichier statique. */
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => { bootstrap().catch(() => {}); });
} else {
  bootstrap().catch(() => {});
}

_log('info', 'NGAPUpdateManager v1 prêt — window.NGAPUpdateManager disponible');

